#!/bin/bash\n\n# Barcode Management System - Quick Start Script (Linux/Mac)\n# Run this after initial installation to start the application\n\necho \"═══════════════════════════════════════════════════════════\"\necho \"🚀 Starting Barcode Management System\"\necho \"═══════════════════════════════════════════════════════════\"\necho \"\"\n\n# Colors\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m'\n\n# Check if we're in the right directory\nif [ ! -d \"backend\" ] || [ ! -d \"frontend\" ]; then\n    echo \"${YELLOW}❌ Please run this script from the repository root directory${NC}\"\n    exit 1\nfi\n\necho \"${YELLOW}Starting Backend Server...${NC}\"\necho \"\"\necho \"To start the backend, open a new terminal and run:\"\necho \"${GREEN}cd backend && npm start${NC}\"\necho \"\"\necho \"The backend will be available at: ${GREEN}http://localhost:5000${NC}\"\necho \"\"\n\necho \"${YELLOW}Starting Frontend Application...${NC}\"\necho \"\"\ncd frontend\nnpm start\n\necho \"\"\necho \"${GREEN}✅ Frontend started!${NC}\"\necho \"Application URL: ${GREEN}http://localhost:3000${NC}\"\necho \"\"\n"
